    controller_output_t output = { .compressor_on = false, .vent_open = true, .state = CONTROLLER_STATE_SAFE_VENT };

    if (controller == 0) return output;

    printf("DEBUG step: kind=%d, pressure=%d, door_closed=%d\n", kind, pressure_kpa, door_closed);
    printf("DEBUG step: has_valid_pressure=%d, has_valid_door=%d\n", controller->has_valid_pressure, controller->has_valid_door);

    switch (kind) {
    case 1: // PRESSURE
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = pressure_kpa;
        controller->last_pressure_ms = now_ms;
        if (controller->has_valid_door) {
            printf("DEBUG step: has valid door, calling update_actuators\n");
            controller_update_actuators(controller, pressure_kpa, controller->door_closed);
        } else {
            printf("DEBUG step: no valid door, going to safe vent\n");
            controller_set_safe_vent(controller);
        }
        break;
    case 2: // DOOR_CLOSED
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = now_ms;
        if (controller->has_valid_pressure) {
            printf("DEBUG step: has valid pressure, calling update_actuators\n");
            controller_update_actuators(controller, controller->last_pressure_kpa, controller->door_closed);
        } else {
            printf("DEBUG step: no valid pressure, going to safe vent\n");
            controller_set_safe_vent(controller);
        }
        break;
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    return output;
}

