    printf("=== After init ===\n");
    printf("compressor_on=%d, vent_open=%d, state=%d\n", c.compressor_on, c.vent_open, c.state);

    printf("\n=== Step 1: DOOR_CLOSED ===\n");
    controller_output_t out1 = controller_step(&c, 2, 0, true, 0);
    printf("After step 1: compressor_on=%d, vent_open=%d, state=%d\n", out1.compressor_on, out1.vent_open, out1.state);

    printf("\n=== Step 2: PRESS 35 ===\n");
    controller_output_t out2 = controller_step(&c, 1, 35, false, 0);
    printf("After step 2: compressor_on=%d, vent_open=%d, state=%d\n", out2.compressor_on, out2.vent_open, out2.state);

    return 0;
}
EOF
