    if ((now_ms - controller->last_pressure_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    if (!controller->has_valid_door) {
        return true;
    }
    if ((now_ms - controller->last_door_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    return false;
}

static void controller_set_state(controller_t *controller, bool compressor_on, bool vent_open, controller_state_t state)
{
    controller->compressor_on = compressor_on;
    controller->vent_open = vent_open;
    controller->state = state;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    /* Check for timeout first */
    bool timed_out = controller_is_timeout(controller, input.now_ms);
    if (timed_out) {
        controller_set_safe_vent(controller);
        output.timed_out = true;
    } else {
        /* Apply control policy based on input type */
        switch (input.kind) {
        case CONTROLLER_INPUT_PRESSURE:
            controller->has_valid_pressure = true;
            controller->last_pressure_kpa = input.pressure_kpa;
            controller->last_pressure_ms = input.now_ms;

            /* Determine door state - if we have a valid door reading, use it */
            bool current_door_closed = controller->door_closed;
            if (!controller->has_valid_door) {
                current_door_closed = false;  /* Default to open if no valid reading */
            }

            /* Apply control policy */
            if (current_door_closed) {
                if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                    controller_set_state(controller, true, false, CONTROLLER_STATE_PRESSURIZING);
                } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                    controller_set_state(controller, false, true, CONTROLLER_STATE_RELIEVING);
                }
                /* In band: preserve previous state */
            } else {
                /* Door open - go to safe vent */
                controller_set_safe_vent(controller);
            }
            break;

        case CONTROLLER_INPUT_DOOR_OPEN:
            controller->has_valid_door = true;
            controller->door_closed = false;
            controller->last_door_ms = input.now_ms;
            /* Door open forces safe vent */
            controller_set_safe_vent(controller);
            break;

        case CONTROLLER_INPUT_DOOR_CLOSED:
            controller->has_valid_door = true;
            controller->door_closed = true;
            controller->last_door_ms = input.now_ms;

            /* If we have a valid pressure reading, apply control policy */
            if (controller->has_valid_pressure) {
                if (controller->last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                    controller_set_state(controller, true, false, CONTROLLER_STATE_PRESSURIZING);
                } else if (controller->last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                    controller_set_state(controller, false, true, CONTROLLER_STATE_RELIEVING);
                }
                /* In band: preserve previous state */
            } else {
                /* No valid pressure - go to safe vent */
                controller_set_safe_vent(controller);
            }
            break;

        case CONTROLLER_INPUT_SENSOR_TIMEOUT:
            controller_set_safe_vent(controller);
            output.timed_out = true;
            break;

        case CONTROLLER_INPUT_INVALID_PRESSURE:
        case CONTROLLER_INPUT_INVALID_DOOR:
            controller->has_valid_pressure = false;
            controller->has_valid_door = false;
            controller_set_safe_vent(controller);
            break;

        case CONTROLLER_INPUT_NONE:
            /* No new input - check for timeout */
            if (controller_is_timeout(controller, input.now_ms)) {
                controller_set_safe_vent(controller);
                output.timed_out = true;
            }
            /* If no timeout and no new data, preserve current state */
            break;
        }
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PRESSURIZING:
        return "STATE PRESSURIZING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_RELIEVING:
        return "STATE RELIEVING";
    case CONTROLLER_STATE_SAFE_VENT:
    default:
        return "STATE SAFE_VENT";
    }
}

